import { lazy, Suspense } from "react";
import { useSearchParams } from "react-router-dom";
import { useWiki } from "@/hooks/useWiki";
import { useAuth } from "@/hooks/useAuth";
import { Button } from "@/components/ui/button";
import { Edit2, Eye, Calendar, User, ChevronRight, Share2, Trash2 } from "lucide-react";
import { format } from "date-fns";
import { it } from 'date-fns/locale';
import { toast } from "sonner";

interface MarkdownRendererProps {
  source: string;
  className?: string;
}

const MarkdownRenderer = lazy(async () => {
  const module = await import("@uiw/react-md-editor");
  return {
    default: ({ source, className }: MarkdownRendererProps) => (
      <module.default.Markdown source={source} className={className} />
    ),
  };
});

interface WikiArticleViewProps {
  onEdit: (id: string) => void;
}

export function WikiArticleView({ onEdit }: WikiArticleViewProps) {
  const [searchParams] = useSearchParams();
  const id = searchParams.get("id");
  const { getArticle, deleteArticle } = useWiki();
  const { data: article, isLoading } = getArticle(id || "");
  const { user } = useAuth();

  const canEdit = user?.ruolo === 'ADMIN' || user?.ruolo === 'PM';

  const handleDelete = async () => {
    if (!id || !confirm("Sei sicuro di voler eliminare questo articolo?")) return;
    try {
      await deleteArticle.mutateAsync(id);
      toast.success("Articolo eliminato");
      window.location.assign("/wiki");
    } catch (error) {
      toast.error("Errore durante l'eliminazione");
    }
  };

  if (isLoading) {
    return (
      <div className="flex-1 p-12 space-y-8 animate-pulse">
        <div className="h-12 w-2/3 bg-muted rounded-2xl" />
        <div className="h-6 w-1/3 bg-muted rounded-lg" />
        <div className="space-y-4">
          <div className="h-4 w-full bg-muted rounded-md" />
          <div className="h-4 w-full bg-muted rounded-md" />
          <div className="h-4 w-3/4 bg-muted rounded-md" />
        </div>
      </div>
    );
  }

  if (!article) {
    return (
      <div className="flex-1 flex items-center justify-center text-muted-foreground font-bold italic">
        Seleziona un articolo dalla barra laterale per iniziare a leggere.
      </div>
    );
  }

  return (
    <div className="flex-1 overflow-y-auto custom-scrollbar bg-background">
      <div className="max-w-4xl mx-auto p-12 pt-8 space-y-8 animate-in fade-in slide-in-from-right-4 duration-500">

        {/* Breadcrumb */}
        <nav className="flex items-center gap-2 text-xs font-black uppercase tracking-widest text-muted-foreground border-b border-border/50 pb-4 mb-8">
          <span className="hover:text-primary transition-colors cursor-pointer">Wiki</span>
          <ChevronRight size={12} />
          <span className="hover:text-primary transition-colors cursor-pointer">{article.categoria?.nome}</span>
          <ChevronRight size={12} />
          <span className="text-white truncate max-w-[200px]">{article.titolo}</span>
        </nav>

        {/* Header */}
        <div className="flex flex-col gap-6">
          <div className="flex items-start justify-between gap-4">
            <h1 className="text-5xl font-black tracking-tighter text-white leading-tight">
              {article.titolo}
            </h1>
            <div className="flex items-center gap-2">
              <Button variant="outline" size="icon" className="rounded-xl border-border hover:bg-muted text-muted-foreground hover:text-white">
                <Share2 size={18} />
              </Button>
              {canEdit && (
                <>
                  <Button 
                    onClick={() => onEdit(article.id)}
                    className="gap-2 rounded-xl font-bold bg-primary text-white shadow-lg shadow-primary/20 hover:scale-105 transition-all"
                  >
                    <Edit2 size={18} />
                    Modifica
                  </Button>
                  <Button 
                    onClick={handleDelete}
                    variant="ghost" 
                    size="icon" 
                    className="rounded-xl text-destructive hover:bg-destructive/10"
                  >
                    <Trash2 size={18} />
                  </Button>
                </>
              )}
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-6 text-sm text-muted-foreground font-medium border-y border-border/30 py-4">
            <div className="flex items-center gap-2 bg-muted/30 px-3 py-1.5 rounded-full border border-border/50">
              <User size={16} className="text-primary" />
              <span className="text-white font-bold">{article.autore_nome}</span>
            </div>
            <div className="flex items-center gap-2">
              <Calendar size={16} />
              Aggiornato il {format(new Date(article.ultimo_aggiornamento), "d MMMM yyyy", { locale: it })}
            </div>
            <div className="flex items-center gap-2">
              <Eye size={16} />
              {article.visualizzazioni} visualizzazioni
            </div>
          </div>
        </div>

        {/* Content */}
        <div className="prose prose-invert prose-p:text-muted-foreground prose-headings:text-white prose-headings:font-black prose-a:text-primary max-w-none pt-4 bg-card/10 p-8 rounded-3xl border border-border/20 shadow-inner min-h-[400px]">
          <Suspense fallback={<div className="text-sm text-muted-foreground">Caricamento contenuto...</div>}>
            <MarkdownRenderer
              source={article.contenuto || "*Nessun contenuto*"}
              className="bg-transparent text-lg leading-relaxed font-medium"
            />
          </Suspense>
        </div>

        {/* Footer info */}
        <div className="pt-12 border-t border-border/30 text-center text-xs font-black uppercase tracking-[0.2em] text-muted-foreground/50">
          Fine dell'articolo &bull; Bite Digital Operations
        </div>
      </div>
    </div>
  );
}

import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import axios from '@/lib/api';
import { useAuth } from '@/hooks/useAuth';

interface ChatContextType {
  channels: any[];
  users: any[];
  messages: any[];
  isLoading: boolean;
  activeChannelId: string | null;
  setActiveChannelId: (id: string | null) => void;
  hasMore: boolean;
  typingUsers: string[];
  onlineUsers: Set<string>;
  channelSeenStatus: Record<string, Record<string, string>>;
  unreadCounts: Record<string, number>;
  loadMoreMessages: () => Promise<void>;
  sendMessage: (content: string, type?: string, replyToId?: string) => Promise<void>;
  uploadFile: (file: File) => Promise<any>;
  startDirectChat: (userId: string) => Promise<any>;
  editMessage: (id: string, content: string) => Promise<void>;
  deleteMessage: (id: string) => Promise<void>;
  addReaction: (messageId: string, emoji: string) => Promise<void>;
  removeReaction: (messageId: string, emoji: string) => Promise<void>;
  setTypingStatus: (isTyping: boolean) => void;
  markAsSeen: (channelId: string) => void;
}

const ChatContext = createContext<ChatContextType | undefined>(undefined);

export function ChatProvider({ children }: { children: React.ReactNode }) {
  const { user, isLoading: isAuthLoading } = useAuth();
  const queryClient = useQueryClient();

  const [activeChannelId, setActiveChannelId] = useState<string | null>(() => {
    return new URLSearchParams(window.location.search).get('channel');
  });
  const [typingUsers, setTypingUsers] = useState<string[]>([]);
  const [onlineUsers, setOnlineUsers] = useState<Set<string>>(new Set());
  const [hasMore, setHasMore] = useState(true);
  const [offset, setOffset] = useState(0);
  const [channelSeenStatus, setChannelSeenStatus] = useState<Record<string, Record<string, string>>>({});
  const [unreadCounts, setUnreadCounts] = useState<Record<string, number>>({});

  const ws = useRef<WebSocket | null>(null);
  const activeChannelIdRef = useRef<string | null>(activeChannelId);
  const connectWSRef = useRef<() => Promise<void>>(async () => {});
  const reconnectAttemptsRef = useRef(0);
  const reconnectTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const isUnmountedRef = useRef(false);
  const LIMIT = 50;

  useEffect(() => {
    activeChannelIdRef.current = activeChannelId;
  }, [activeChannelId]);

  // Data Fetching
  const { data: channels, isLoading: isChannelsLoading } = useQuery({
    queryKey: ['chat-channels'],
    queryFn: async () => {
      const res = await axios.get('/chat/channels');
      return res.data;
    },
    enabled: !!user,
    refetchInterval: 60000,
  });

  const { data: users = [] } = useQuery({
    queryKey: ['chat-users'],
    queryFn: async () => {
      const res = await axios.get('/chat/users');
      return res.data;
    },
    enabled: !!user,
  });

  const { data: messages = [], isLoading: isMessagesLoading } = useQuery({
    queryKey: ['chat-messages', activeChannelId],
    queryFn: async () => {
      if (!activeChannelId) return [];
      const res = await axios.get(`/chat/channels/${activeChannelId}/messages?limit=${LIMIT}&offset=0`);
      if (res.data.length < LIMIT) setHasMore(false);
      else setHasMore(true);
      setOffset(res.data.length);
      return res.data;
    },
    enabled: !!activeChannelId,
    staleTime: Infinity,
  });

  const loadMoreMessages = useCallback(async () => {
    if (!activeChannelId || !hasMore) return;
    try {
      const res = await axios.get(`/chat/channels/${activeChannelId}/messages?limit=${LIMIT}&offset=${offset}`);
      if (res.data.length < LIMIT) setHasMore(false);
      queryClient.setQueryData(['chat-messages', activeChannelId], (prev: any) => {
        return [...res.data, ...(prev || [])];
      });
      setOffset(prev => prev + res.data.length);
    } catch (err) {
      console.error("Load more failed", err);
    }
  }, [activeChannelId, offset, hasMore, queryClient]);

  // WebSocket
  const connectWS = useCallback(async () => {
    if (!user || isUnmountedRef.current) return;
    if (
      ws.current &&
      (ws.current.readyState === WebSocket.OPEN || ws.current.readyState === WebSocket.CONNECTING)
    ) return;

    const scheduleReconnect = () => {
      if (isUnmountedRef.current) return;
      if (reconnectTimeoutRef.current) clearTimeout(reconnectTimeoutRef.current);
      const delay = Math.min(1000 * Math.pow(2, reconnectAttemptsRef.current), 30000);
      reconnectAttemptsRef.current += 1;
      reconnectTimeoutRef.current = setTimeout(() => {
        void connectWSRef.current();
      }, delay);
    };

    try {
      const ticketResponse = await axios.post('/chat/ws-ticket');
      if (isUnmountedRef.current) return;

      const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
      const wsUrl = `${protocol}//${window.location.host}/api/v1/chat/ws?ticket=${encodeURIComponent(ticketResponse.data.ticket)}`;
      const socket = new WebSocket(wsUrl);
      ws.current = socket;

      socket.onopen = () => {
        reconnectAttemptsRef.current = 0;
      };

      socket.onmessage = (event) => {
        const data = JSON.parse(event.data);
        const currentChannelId = activeChannelIdRef.current;

        switch (data.type) {
          case 'new_message': {
            queryClient.setQueryData(['chat-channels'], (old: any) => {
              return old?.map((c: any) => c.id === data.message.canale_id ? {
                ...c,
                last_message: data.message.tipo !== 'testo' ? '[Allegato]' : data.message.contenuto,
                last_message_at: data.message.created_at
              } : c);
            });
            if (data.message.canale_id === currentChannelId) {
              queryClient.setQueryData(['chat-messages', currentChannelId], (prev: any) => {
                // Dedup: se il messaggio è già presente non aggiungerlo di nuovo
                const existing = (prev || []) as any[];
                if (existing.some((m: any) => m.id === data.message.id)) return existing;
                return [...existing, data.message];
              });
            } else {
              setUnreadCounts(prev => ({
                ...prev,
                [data.message.canale_id]: (prev[data.message.canale_id] || 0) + 1
              }));
            }
            break;
          }
          case 'message_edited': {
            const targetChannel = data.canale_id || currentChannelId;
            if (targetChannel) {
              queryClient.setQueryData(['chat-messages', targetChannel], (prev: any) =>
                prev?.map((m: any) =>
                  m.id === data.message_id
                    ? { ...m, contenuto: data.contenuto, updated_at: new Date().toISOString(), modificato: true }
                    : m
                )
              );
            }
            break;
          }
          case 'delete_message': {
            const targetChannel = data.canale_id || currentChannelId;
            if (targetChannel) {
              queryClient.setQueryData(['chat-messages', targetChannel], (prev: any) =>
                prev?.filter((m: any) => m.id !== data.message_id)
              );
            }
            break;
          }
          case 'reaction_added': {
            const targetChannel = data.canale_id || currentChannelId;
            if (targetChannel) {
              queryClient.setQueryData(['chat-messages', targetChannel], (prev: any) =>
                prev?.map((m: any) => {
                  if (m.id !== data.message_id) return m;
                  const alreadyHas = m.reazioni?.some((r: any) => r.user_id === data.user_id && r.emoji === data.emoji);
                  if (alreadyHas) return m;
                  return {
                    ...m,
                    reazioni: [...(m.reazioni || []), { id: crypto.randomUUID(), emoji: data.emoji, user_id: data.user_id, user_nome: data.user_nome, created_at: new Date().toISOString() }]
                  };
                })
              );
            }
            break;
          }
          case 'reaction_removed': {
            const targetChannel = data.canale_id || currentChannelId;
            if (targetChannel) {
              queryClient.setQueryData(['chat-messages', targetChannel], (prev: any) =>
                prev?.map((m: any) => {
                  if (m.id !== data.message_id) return m;
                  return {
                    ...m,
                    reazioni: (m.reazioni || []).filter(
                      (reaction: any) => !(reaction.user_id === data.user_id && reaction.emoji === data.emoji)
                    )
                  };
                })
              );
            }
            break;
          }
          case 'user_typing':
            if (data.channel_id === currentChannelId) {
              setTypingUsers(prev => data.is_typing ? [...new Set([...prev, data.user_nome])] : prev.filter(n => n !== data.user_nome));
            }
            break;
          case 'user_presence':
            setOnlineUsers(prev => {
              const next = new Set(prev);
              if (data.status === 'online') next.add(data.user_id);
              else next.delete(data.user_id);
              return next;
            });
            break;
          case 'message_seen':
            setChannelSeenStatus((prev) => ({
              ...prev,
              [data.channel_id]: {
                ...(prev[data.channel_id] || {}),
                [data.user_id]: data.last_seen_at,
              },
            }));
            break;
        }
      };

      socket.onclose = () => {
        if (ws.current === socket) {
          ws.current = null;
        }
        scheduleReconnect();
      };

      socket.onerror = () => socket.close();
    } catch (err) {
      console.error("WS bootstrap failed", err);
      scheduleReconnect();
    }
  }, [user, queryClient]);

  useEffect(() => {
    connectWSRef.current = connectWS;
  }, [connectWS]);

  useEffect(() => {
    isUnmountedRef.current = false;
    // Don't connect if loading auth, or no token, or no user (e.g. on login page)
    if (isAuthLoading || !user) return;
    
    void connectWS();
    return () => {
      isUnmountedRef.current = true;
      if (reconnectTimeoutRef.current) clearTimeout(reconnectTimeoutRef.current);
      
      if (ws.current) {
        // Remove listeners before closing to avoid "closed before established" console noise 
        // and prevent any further logic from firing during unmount
        const socket = ws.current;
        socket.onopen = null;
        socket.onmessage = null;
        socket.onerror = null;
        socket.onclose = null;
        
        // Only close if fully open to avoid "closed before established" warning.
        // We already cleared listeners, so it won't trigger any logic if it's connecting.
        if (socket.readyState === WebSocket.OPEN) {
          socket.close();
        }
        ws.current = null;
      }
    };
  }, [user, isAuthLoading, connectWS]);

  // Actions
  const sendMessage = useCallback(async (content: string, type: string = 'testo', replyToId?: string) => {
    if (!activeChannelId) return;
    const activeChannel = channels?.find((c: any) => c.id === activeChannelId);
    await axios.post('/chat/messages', {
      canale_id: activeChannelId,
      progetto_id: activeChannel?.progetto_id,
      contenuto: content,
      tipo: type,
      risposta_a: replyToId
    });
  }, [activeChannelId, channels]);

  const uploadFile = useCallback(async (file: File) => {
    const formData = new FormData();
    formData.append('file', file);
    const res = await axios.post('/uploads', formData, { headers: { 'Content-Type': 'multipart/form-data' } });
    return res.data;
  }, []);

  const editMessage = useCallback(async (id: string, content: string) => {
    await axios.patch(`/chat/messages/${id}`, { contenuto: content });
  }, []);

  const deleteMessage = useCallback(async (id: string) => {
    await axios.delete(`/chat/messages/${id}`);
  }, []);

  const addReaction = useCallback(async (messageId: string, emoji: string) => {
    await axios.post(`/chat/messages/${messageId}/reactions`, { emoji });
  }, []);

  const removeReaction = useCallback(async (messageId: string, emoji: string) => {
    await axios.delete(`/chat/messages/${messageId}/reactions/${encodeURIComponent(emoji)}`);
  }, []);

  const setTypingStatus = useCallback((isTyping: boolean) => {
    if (ws.current?.readyState === WebSocket.OPEN && activeChannelId) {
      ws.current.send(JSON.stringify({ type: 'typing', channel_id: activeChannelId, is_typing: isTyping }));
    }
  }, [activeChannelId]);

  const markAsSeen = useCallback((channelId: string) => {
    setUnreadCounts(prev => prev[channelId] === 0 ? prev : { ...prev, [channelId]: 0 });
    if (ws.current?.readyState === WebSocket.OPEN) {
      ws.current.send(JSON.stringify({ type: 'message_seen', channel_id: channelId }));
    }
  }, []);

  const startDirectChat = useCallback(async (userId: string) => {
    try {
      const res = await axios.post('/chat/channels/direct', { other_user_id: userId });
      const newChannel = res.data;
      queryClient.setQueryData(['chat-channels'], (old: any) => {
        if (!old?.find((c: any) => c.id === newChannel.id)) return [newChannel, ...(old || [])];
        return old;
      });
      setActiveChannelId(newChannel.id);
      return newChannel;
    } catch (err) {
      console.error("Failed to start DM", err);
    }
  }, [queryClient]);

  const value = {
    channels: channels || [],
    users,
    messages,
    isLoading: isAuthLoading || isChannelsLoading || isMessagesLoading,
    activeChannelId,
    setActiveChannelId,
    hasMore,
    typingUsers,
    onlineUsers,
    channelSeenStatus,
    unreadCounts,
    loadMoreMessages,
    sendMessage,
    uploadFile,
    startDirectChat,
    editMessage,
    deleteMessage,
    addReaction,
    removeReaction,
    setTypingStatus,
    markAsSeen
  };

  return <ChatContext.Provider value={value}>{children}</ChatContext.Provider>;
}

export function useChatContext() {
  const context = useContext(ChatContext);
  if (context === undefined) {
    throw new Error('useChatContext must be used within a ChatProvider');
  }
  return context;
}

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { api } from "@/lib/api";
import { toast } from "sonner";
import type { WikiCategory, WikiArticle } from "@/types/wiki";

export function useWiki() {
  const queryClient = useQueryClient();

  const categories = useQuery({
    queryKey: ["wiki-categories"],
    queryFn: async () => {
      const res = await api.get<WikiCategory[]>("/wiki/categorie");
      return res.data;
    },
  });

  const useArticles = (categoria_id?: string) => useQuery({
    queryKey: ["wiki-articles", categoria_id],
    queryFn: async () => {
      const url = categoria_id ? `/wiki/articoli?categoria_id=${categoria_id}` : "/wiki/articoli";
      const res = await api.get<WikiArticle[]>(url);
      return res.data;
    },
  });

  const useArticle = (id: string) => useQuery({
    queryKey: ["wiki-article", id],
    queryFn: async () => {
      const res = await api.get<WikiArticle>(`/wiki/articoli/${id}`);
      return res.data;
    },
    enabled: !!id,
  });

  const createArticle = useMutation({
    mutationFn: async (data: Partial<WikiArticle>) => {
      const res = await api.post<WikiArticle>("/wiki/articoli", data);
      return res.data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["wiki-articles"], exact: false });
    },
    onError: (err: any) => {
      toast.error(err?.response?.data?.detail ?? "Errore nella creazione dell'articolo");
    },
  });

  const updateArticle = useMutation({
    mutationFn: async ({ id, ...data }: Partial<WikiArticle> & { id: string }) => {
      const res = await api.patch<WikiArticle>(`/wiki/articoli/${id}`, data);
      return res.data;
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ["wiki-articles"], exact: false });
      queryClient.invalidateQueries({ queryKey: ["wiki-article", data.id], exact: false });
    },
    onError: (err: any) => {
      toast.error(err?.response?.data?.detail ?? "Errore nel salvataggio dell'articolo");
    },
  });

  const deleteArticle = useMutation({
    mutationFn: async (id: string) => {
      await api.delete(`/wiki/articoli/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["wiki-articles"], exact: false });
    },
    onError: (err: any) => {
      toast.error(err?.response?.data?.detail ?? "Errore nell'eliminazione dell'articolo");
    },
  });

  const useSearchArticles = (q: string) => useQuery({
    queryKey: ["wiki-search", q],
    queryFn: async () => {
      const res = await api.get<WikiArticle[]>(`/wiki/cerca?q=${q}`);
      return res.data;
    },
    enabled: q.length > 2,
  });

  return {
    categories,
    articles: useArticles,
    getArticle: useArticle,
    createArticle,
    updateArticle,
    deleteArticle,
    searchArticles: useSearchArticles,
  };
}
